from interpolation.h
 inline rectangle tform_object (
            const point_transform_affine& tran,
            const rectangle& rect
        )
        {
            return centered_rect(tran(center(rect)), rect.width(), rect.height());
        }

when i changed it into below, this problem was fixed. (i saw below code from imglab)
         inline rectangle tform_object (
            const point_transform_affine& tran,
            const rectangle& rect
        ){
            dlib::rectangle newrect;
            newrect += tran(rect.tl_corner());
            newrect += tran(rect.tr_corner());
            newrect += tran(rect.bl_corner());
            newrect += tran(rect.br_corner());
            const auto ratio = std::sqrt(rect.area() / (double)newrect.area());
            newrect = centered_rect(newrect, newrect.width()*ratio, newrect.height()*ratio);
            return newrect;
        }

